// Multi Accounts: Post as dropdown (static guard prevents duplicate output)
static $multiaccounts_post_as_shown = false;
if (!$multiaccounts_post_as_shown && !empty($context['user']['multiaccounts']) && count($context['user']['multiaccounts']) > 1)
{
	$multiaccounts_post_as_shown = true;
	echo '
				<div class="multiaccounts_post_as">
					<label for="multiaccount_post_as"><strong>', $txt['multiaccounts_post_as'], ':</strong></label>
					<select name="multiaccount_post_as" id="multiaccount_post_as">';

	foreach ($context['user']['multiaccounts'] as $ma_id => $ma_account)
		echo '
						<option value="', $ma_id, '"', $ma_id == $context['user']['id'] ? ' selected' : '', '>', $ma_account['name'], '</option>';

	echo '
					</select>
				</div>';
}

